"""Evaluation Regression CheckerThis script compares two agent evaluation run summaries and detectsperformance regressions.It is designed to enforce evaluation discipline in CI pipelines byfailing if a new evaluation run performs worse than a pinned baseline.The script compares:- pass_rate- avg_latency_sec- avg_retrieved_count- avg_retry_countOnly pass_rate currently triggers a failure condition.Usage:    python scripts/compare_eval_runs.py \        evals/agent/logs/runs/new_summary.json \        evals/agent/logs/baseline_summary.jsonExample:    python scripts/compare_eval_runs.py \        evals/agent/logs/runs/2026-03-10_summary.json \        evals/agent/logs/baseline_summary.jsonExit codes:    0 → PASS (no regression)    1 → FAIL (regression detected)Typical CI usage:    python scripts/compare_eval_runs.py new_summary.json baseline.jsonIf the new run degrades pass_rate beyond the allowed threshold,the script exits with code 1 so CI fails."""import jsonimport sysfrom pathlib import Path# -------------------------# Config# -------------------------# Allowed drop in pass rate before failingPASS_RATE_TOLERANCE = 0.02# -------------------------# Helpers# -------------------------def load_summary(path: Path) -> dict:    with open(path, "r") as f:        return json.load(f)def print_metric_delta(name: str, new: float | None, baseline: float | None):    if new is None or baseline is None:        print(f"{name}: unavailable")        return    delta = new - baseline    sign = "+" if delta >= 0 else "-"    print(f"{name}: {new:.4f} ({sign}{abs(delta):.4f} vs baseline {baseline:.4f})")# -------------------------# Main# -------------------------def main():    if len(sys.argv) != 3:        print("Usage: python compare_eval_runs.py <new_summary> <baseline_summary>")        sys.exit(2)    new_path = Path(sys.argv[1])    baseline_path = Path(sys.argv[2])    if not new_path.exists():        print(f"ERROR: new summary not found: {new_path}")        sys.exit(2)    if not baseline_path.exists():        print(f"ERROR: baseline summary not found: {baseline_path}")        sys.exit(2)    new = load_summary(new_path)    baseline = load_summary(baseline_path)    print("\n=== Eval Comparison ===\n")    print_metric_delta("pass_rate", new.get("pass_rate"), baseline.get("pass_rate"))    print_metric_delta("avg_latency_sec", new.get("avg_latency_sec"), baseline.get("avg_latency_sec"))    print_metric_delta("avg_retrieved_count", new.get("avg_retrieved_count"), baseline.get("avg_retrieved_count"))    print_metric_delta("avg_retry_count", new.get("avg_retry_count"), baseline.get("avg_retry_count"))    print()    # -------------------------    # Regression check    # -------------------------    new_pass = new.get("pass_rate")    base_pass = baseline.get("pass_rate")    if new_pass is None or base_pass is None:        print("WARNING: pass_rate missing; cannot enforce regression check.")        sys.exit(0)    drop = base_pass - new_pass    if drop > PASS_RATE_TOLERANCE:        print("❌ REGRESSION DETECTED")        print(f"Pass rate dropped by {drop:.4f} (tolerance {PASS_RATE_TOLERANCE:.4f})")        sys.exit(1)    print("✅ PASS — no regression detected")    sys.exit(0)if __name__ == "__main__":    main()